// useChordShortcut.ts
import { useEffect, useRef, useState } from 'react';
export function useChordShortcut(prefix: string, mappings: Record<string, () => void>) {
  const [armed, setArmed] = useState(false);
  const timerRef = useRef<number | null>(null);
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (!armed && e.key === prefix) { setArmed(true); if (timerRef.current) window.clearTimeout(timerRef.current); timerRef.current = window.setTimeout(() => setArmed(false), 800); }
      else if (armed && mappings[e.key]) { e.preventDefault(); mappings[e.key](); setArmed(false); if (timerRef.current) window.clearTimeout(timerRef.current); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [prefix, mappings, armed]);
  return armed;
}

