import { useState } from 'react';
export function MinDurationButton({ label, loadingLabel, onClick, minDurationMs = 600 }: { label: string; loadingLabel: string; onClick: () => Promise<void>; minDurationMs?: number }) {
  const [loading, setLoading] = useState(false);
  const handle = async () => {
    setLoading(true);
    const start = Date.now();
    try { await onClick(); } finally {
      const elapsed = Date.now() - start;
      if (elapsed < minDurationMs) await new Promise(r => setTimeout(r, minDurationMs - elapsed));
      setLoading(false);
    }
  };
  return <button type="button" onClick={handle} disabled={loading} aria-busy={loading} className="h-10 px-6 bg-[oklch(0.55_0.18_250)] text-white text-[14px] font-medium rounded-md min-w-[140px] disabled:opacity-80">{loading ? loadingLabel : label}</button>;
}

// TargetAreaChart.tsx
export function TargetAreaChart({ values, target, width = 480, height = 240 }: { values: ReadonlyArray<number>; target: number; width?: number; height?: number }) {
  const max = Math.max(...values, target) * 1.1;
  const xScale = (i: number) => (i / (values.length - 1)) * width;
  const yScale = (v: number) => height - (v / max) * height;
  const targetY = yScale(target);
  // Build area path
  const areaPath = values.map((v, i) => `${i ? 'L' : 'M'}${xScale(i).toFixed(1)} ${yScale(v).toFixed(1)}`).join(' ') + ` L${width} ${height} L0 ${height} Z`;
  // Build above/below target masks (visual approximation via clip)
  return (
    <svg width={width} height={height}>
      <defs>
        <clipPath id="above"><rect x={0} y={0} width={width} height={targetY} /></clipPath>
        <clipPath id="below"><rect x={0} y={targetY} width={width} height={height - targetY} /></clipPath>
      </defs>
      <path d={areaPath} fill="oklch(0.7 0.12 145 / 0.3)" clipPath="url(#above)" />
      <path d={areaPath} fill="oklch(0.7 0.12 25 / 0.3)" clipPath="url(#below)" />
      <path d={values.map((v, i) => `${i ? 'L' : 'M'}${xScale(i).toFixed(1)} ${yScale(v).toFixed(1)}`).join(' ')} stroke="oklch(0.4 0.005 250)" strokeWidth="1.5" fill="none" />
      <line x1={0} y1={targetY} x2={width} y2={targetY} stroke="oklch(0.55 0.18 250)" strokeWidth="2" strokeDasharray="4 4" />
      <text x={width - 4} y={targetY - 4} fontSize="11" textAnchor="end" fill="oklch(0.55 0.18 250)">Goal: {target}</text>
    </svg>
  );
}

