// InfiniteCanvas.tsx
import { useRef, useState } from 'react';
export function InfiniteCanvas({ children }: { children: React.ReactNode }) {
  const [transform, setTransform] = useState({ x: 0, y: 0, scale: 1 });
  const isDragging = useRef(false);
  const lastPointer = useRef({ x: 0, y: 0 });
  const onPointerDown = (e: React.PointerEvent) => { isDragging.current = true; lastPointer.current = { x: e.clientX, y: e.clientY }; };
  const onPointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    setTransform(t => ({ ...t, x: t.x + e.clientX - lastPointer.current.x, y: t.y + e.clientY - lastPointer.current.y }));
    lastPointer.current = { x: e.clientX, y: e.clientY };
  };
  const onPointerUp = () => { isDragging.current = false; };
  const onWheel = (e: React.WheelEvent) => { setTransform(t => ({ ...t, scale: Math.max(0.1, Math.min(5, t.scale * (1 - e.deltaY * 0.001))) })); };
  return (
    <div onPointerDown={onPointerDown} onPointerMove={onPointerMove} onPointerUp={onPointerUp} onWheel={onWheel} className="w-full h-screen overflow-hidden cursor-grab" style={{ background: `radial-gradient(circle at 50% 50%, oklch(0.93 0.005 250) 1px, transparent 1px) 0 0 / ${24 * transform.scale}px ${24 * transform.scale}px` }}>
      <div style={{ transform: `translate(${transform.x}px, ${transform.y}px) scale(${transform.scale})`, transformOrigin: '0 0' }}>{children}</div>
    </div>
  );
}

