import { useState, useId, useEffect } from 'react';
export function AccessibleTooltip({ content, children }: { content: string; children: React.ReactElement }) {
  const id = useId();
  const [show, setShow] = useState(false);
  useEffect(() => {
    if (!show) return;
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') setShow(false); };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [show]);
  const child = children as React.ReactElement<any>;
  return (
    <>
      {/* In real impl: clone child with aria-describedby + handlers */}
      <span aria-describedby={show ? id : undefined} onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)} onFocus={() => setShow(true)} onBlur={() => setShow(false)}>{child}</span>
      {show && <div id={id} role="tooltip" className="absolute z-50 px-2.5 py-1.5 bg-[oklch(0.18_0.005_250)] text-white text-[12px] rounded">{content}</div>}
    </>
