// NumberInputWithKeys.tsx
export function NumberInputWithKeys({ value, onChange, min, max }: { value: number; onChange: (v: number) => void; min?: number; max?: number }) {
  const onKey = (e: React.KeyboardEvent<HTMLInputElement>) => {
    let step = 0;
    if (e.key === 'ArrowUp') step = 1;
    else if (e.key === 'ArrowDown') step = -1;
    if (step === 0) return;
    e.preventDefault();
    if (e.shiftKey) step *= 10;
    if (e.metaKey || e.ctrlKey) step *= 100;
    const next = value + step;
    onChange(min != null ? Math.max(min, max != null ? Math.min(max, next) : next) : (max != null ? Math.min(max, next) : next));
  };
  return <input type="number" value={value} onChange={(e) => onChange(Number(e.target.value))} onKeyDown={onKey} className="w-24 h-9 px-3 text-[14px] tabular-nums font-mono border border-[oklch(0.85_0.005_250)] rounded outline-none focus:border-[oklch(0.55_0.18_250)]" />;
}

