import { useState } from 'react';
export interface ChartEvent { id: string; t: number; kind: string; color: string; label: string; }
export function ChartWithAnnotations({ data, events, width = 600 }: { data: ReadonlyArray<{ t: number; v: number }>; events: ReadonlyArray<ChartEvent>; width?: number }) {
  const [hoverEvent, setHoverEvent] = useState<ChartEvent | null>(null);
  const tMin = data[0]?.t ?? 0, tMax = data[data.length - 1]?.t ?? 1;
  const xScale = (t: number) => ((t - tMin) / (tMax - tMin)) * width;
  return (
    <div>
      <svg width={width} height={200}>
        <path d={data.map((p, i) => `${i ? 'L' : 'M'}${xScale(p.t).toFixed(1)} ${(200 - p.v).toFixed(1)}`).join(' ')} stroke="oklch(0.55 0.18 250)" fill="none" />
      </svg>
      <svg width={width} height={16} className="block">
        {events.map(e => <rect key={e.id} x={xScale(e.t) - 1} y={0} width={2} height={16} fill={e.color} onMouseEnter={() => setHoverEvent(e)} onMouseLeave={() => setHoverEvent(null)} />)}
      </svg>
      {hoverEvent && <div className="text-[12px] mt-1" style={{ color: hoverEvent.color }}>{hoverEvent.label}</div>}
    </div>
