// EmailListInput.tsx
import { useState } from 'react';
function isValidEmail(e: string): boolean { return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e); }
export function EmailListInput({ value, onChange }: { value: ReadonlyArray<string>; onChange: (v: ReadonlyArray<string>) => void }) {
  const [input, setInput] = useState('');
  const addEmails = (raw: string) => {
    const parts = raw.split(/[,;\n\s]+/).map(p => p.trim()).filter(Boolean);
    const fresh = parts.filter(p => !value.includes(p));
    onChange([...value, ...fresh]);
  };
  return (
    <div className="flex flex-wrap items-center gap-1 min-h-9 px-2 py-1 border border-[oklch(0.85_0.005_250)] rounded focus-within:border-[oklch(0.55_0.18_250)]">
      {value.map((e, i) => <span key={i} className={`inline-flex items-center gap-1 px-2 py-0.5 text-[12px] rounded ${isValidEmail(e) ? 'bg-[oklch(0.95_0.005_250)]' : 'bg-[oklch(0.95_0.04_25)] text-[oklch(0.4_0.16_25)]'}`}>{e}<button type="button" onClick={() => onChange(value.filter((_, j) => j !== i))} aria-label={`Remove ${e}`}>\u00D7</button></span>)}
      <input value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ',' || e.key === ';') { e.preventDefault(); if (input) { addEmails(input); setInput(''); } } else if (e.key === 'Backspace' && input === '' && value.length > 0) onChange(value.slice(0, -1)); }} onPaste={(e) => { const text = e.clipboardData.getData('text'); if (/[,;\n]/.test(text)) { e.preventDefault(); addEmails(text); } }} className="flex-1 min-w-[120px] outline-none text-[14px]" />
    </div>
  );
}

