function highlight(text: string, query: string) {
  if (!query) return text;
  const parts = text.split(new RegExp(`(${query})`, 'gi'));
  return parts.map((p, i) => p.toLowerCase() === query.toLowerCase() ? <mark key={i} className="bg-[oklch(0.95_0.15_60)] text-[oklch(0.18_0.01_60)]">{p}</mark> : p);
}
export function HighlightedResults({ results, query }: { results: ReadonlyArray<{ id: string; title: string; path: string }>; query: string }) {
  return (
    <ul>{results.map(r => (
      <li key={r.id} className="px-3 py-2 border-b border-[oklch(0.95_0.005_250)]">
        <div className="text-[13px] font-medium">{highlight(r.title, query)}</div>
        <div className="text-[11px] text-[oklch(0.55_0.005_250)] font-mono">{highlight(r.path, query)}</div>
      </li>
    ))}</ul>
  );
}

// KeyboardModal.tsx (re-presented compact)
import { useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
export function KeyboardModal({ open, onClose, children }: { open: boolean; onClose: () => void; children: React.ReactNode }) {
  const ref = useRef<HTMLDivElement | null>(null);
  const prevFocus = useRef<HTMLElement | null>(null);
  useEffect(() => {
    if (!open) return;
    prevFocus.current = document.activeElement as HTMLElement | null;
    const sel = 'a, button, input, select, textarea, [tabindex]:not([tabindex="-1"])';
    const focusables = () => Array.from(ref.current?.querySelectorAll<HTMLElement>(sel) ?? []);
    focusables()[0]?.focus();
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
      else if (e.key === 'Tab') {
        const f = focusables(); if (f.length === 0) return;
        const first = f[0], last = f[f.length - 1];
        if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
        else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
      }
    };
    document.addEventListener('keydown', onKey);
    return () => { document.removeEventListener('keydown', onKey); prevFocus.current?.focus(); };
  }, [open, onClose]);
  if (!open) return null;
  return createPortal(<div role="dialog" aria-modal="true" className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={onClose}><div ref={ref} onClick={(e) => e.stopPropagation()} className="bg-white rounded-lg p-6 max-w-lg">{children}</div></div>, document.body);
}

// EditLock.tsx
import { useEffect, useState } from 'react';
export function EditLock({ ownerName, lockExpiresAt }: { ownerName: string | null; lockExpiresAt: number | null }) {
  const [now, setNow] = useState(Date.now());
  useEffect(() => { const t = setInterval(() => setNow(Date.now()), 1000); return () => clearInterval(t); }, []);
  if (!ownerName || !lockExpiresAt || lockExpiresAt < now) return null;
  const remaining = Math.max(0, Math.ceil((lockExpiresAt - now) / 1000));
  return (
    <div role="status" className="px-3 py-1.5 text-[12px] rounded" style={{ background: 'oklch(0.95 0.08 60)', color: 'oklch(0.35 0.14 60)' }}>
      <strong>{ownerName}</strong> is editing \u00B7 {remaining}s
    </div>
  );
}

// ProgressRing.tsx
import { useEffect, useState } from 'react';
export function ProgressRing({ value, max, size = 64 }: { value: number; max: number; size?: number }) {
  const [completed, setCompleted] = useState(false);
  useEffect(() => { if (value >= max && !completed) { setCompleted(true); setTimeout(() => setCompleted(false), 600); } }, [value, max, completed]);
  const r = size / 2 - 4; const c = 2 * Math.PI * r;
  const pct = Math.min(1, value / max);
  return (
    <svg width={size} height={size} aria-label={`${Math.round(pct * 100)}% complete`}>
      <circle cx={size/2} cy={size/2} r={r} stroke="oklch(0.93 0.005 250)" strokeWidth="4" fill="none" />
      <circle cx={size/2} cy={size/2} r={r} stroke="oklch(0.55 0.18 250)" strokeWidth="4" fill="none" strokeDasharray={c} strokeDashoffset={c * (1 - pct)} strokeLinecap="round" transform={`rotate(-90 ${size/2} ${size/2})`} style={{ transition: 'stroke-dashoffset 400ms cubic-bezier(0.22, 1, 0.36, 1)', filter: completed ? 'drop-shadow(0 0 8px oklch(0.55 0.18 250 / 0.6))' : 'none' }} />
      <text x={size/2} y={size/2 + 4} fontSize={size / 4} textAnchor="middle" fill="oklch(0.18 0.005 250)" className="tabular-nums">{Math.round(pct * 100)}%</text>
    </svg>
  );
}

// MultiSegmentProgress.tsx
import { useState } from 'react';
export function MultiSegmentProgress({ segments, total }: { segments: ReadonlyArray<{ id: string; label: string; value: number; color: string }>; total: number }) {
  const [hoverId, setHoverId] = useState<string | null>(null);
  return (
    <div>
      <div className="flex h-3 rounded-full overflow-hidden bg-[oklch(0.93_0.005_250)]">
        {segments.map(s => <div key={s.id} className="hover:brightness-110 transition-[filter]" style={{ width: `${(s.value / total) * 100}%`, background: s.color }} onMouseEnter={() => setHoverId(s.id)} onMouseLeave={() => setHoverId(null)} />)}
      </div>
      <div className="flex flex-wrap gap-3 mt-2 text-[11px]">
        {segments.map(s => <div key={s.id} className="flex items-center gap-1" style={{ opacity: !hoverId || hoverId === s.id ? 1 : 0.4 }}><span className="w-2 h-2 rounded" style={{ background: s.color }} />{s.label} {Math.round(s.value)}</div>)}
      </div>
    </div>
  );
}

