import { useEffect } from 'react';
export function useMagicLinkSync(email: string, onVerified: () => void) {
  useEffect(() => {
    if (typeof BroadcastChannel === 'undefined') return;
    const ch = new BroadcastChannel('magic-link');
    ch.onmessage = (e) => { if (e.data?.email === email && e.data?.verified) onVerified(); };
    return () => ch.close();
  }, [email, onVerified]);
}
